CREATE TABLE public.ai_conversations (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL, titulo TEXT NOT NULL DEFAULT 'Nova conversa', created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now()); ALTER TABLE public.ai_conversations ENABLE ROW LEVEL SECURITY; CREATE POLICY "own conv all" ON public.ai_conversations FOR ALL TO authenticated USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id); CREATE TABLE public.ai_messages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), conversation_id UUID NOT NULL REFERENCES public.ai_conversations(id) ON DELETE CASCADE, user_id UUID NOT NULL, role TEXT NOT NULL, content TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); ALTER TABLE public.ai_messages ENABLE ROW LEVEL SECURITY; CREATE POLICY "own msg all" ON public.ai_messages FOR ALL TO authenticated USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id); CREATE TABLE public.ai_dashboard_cache (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL, periodo TEXT NOT NULL, insights JSONB NOT NULL DEFAULT '[]'::jsonb, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); ALTER TABLE public.ai_dashboard_cache ENABLE ROW LEVEL SECURITY; CREATE POLICY "own cache all" ON public.ai_dashboard_cache FOR ALL TO authenticated USING (auth.uid() = user_id) WITH CHECK (auth.uid() = user_id);